WITH LatestReports AS ( SELECT TARGET_MEMBER_ID, REASON, RESULT_STATUS, CREATED_AT, /* 승인(ACCEPTED)된 신고 사유를 최우선 순위로 정렬하여 바인딩 */ ROW_NUMBER() OVER (PARTITION BY TARGET_MEMBER_ID ORDER BY CASE WHEN RESULT_STATUS = 'ACCEPTED' THEN 1 ELSE 2 END, CREATED_AT DESC) as rn FROM MEMBER_REPORT_HISTORY ), ReportStats AS ( SELECT TARGET_MEMBER_ID, /* [수정] 게시글 관리자가 '승인(ACCEPTED)' 처리한 유효 신고 건수만 합산 */ COUNT(CASE WHEN RESULT_STATUS = 'ACCEPTED' THEN 1 END) AS REPORT_COUNT, MAX(CASE WHEN RESULT_STATUS = 'ACCEPTED' THEN CREATED_AT END) AS LATEST_REPORT_DATE FROM MEMBER_REPORT_HISTORY GROUP BY TARGET_MEMBER_ID ), PagedMembers AS ( SELECT m.MEMBER_ID, m.NICKNAME, m.EMAIL, m.ROLE, m.STATUS, m.SOCIAL_PROVIDER AS provider, TO_CHAR(m.CREATED_AT, 'YYYY.MM.DD HH24:MI') AS joined_at, TO_CHAR(m.LAST_LOGIN, 'YYYY.MM.DD HH24:MI') AS last_login, NVL(s.REPORT_COUNT, 0) AS reports, r.REASON AS report_reason, TO_CHAR(s.LATEST_REPORT_DATE, 'YYYY.MM.DD') AS last_report_date, NVL(r.RESULT_STATUS, '없음') AS result_status, TO_CHAR(m.SUSPENSION_END_DATE, 'YYYY.MM.DD') AS suspension_end_date, ROW_NUMBER() OVER (
ORDER BY NVL(s.REPORT_COUNT, 0) DESC, m.CREATED_AT DESC
ORDER BY m.LAST_LOGIN DESC NULLS LAST, m.CREATED_AT DESC
ORDER BY m.CREATED_AT ASC
ORDER BY m.CREATED_AT DESC
) AS rnum FROM MEMBER m LEFT JOIN ReportStats s ON m.MEMBER_ID = s.TARGET_MEMBER_ID LEFT JOIN LatestReports r ON m.MEMBER_ID = r.TARGET_MEMBER_ID AND r.rn = 1
m.ROLE != 'ADMIN'
AND ( m.MEMBER_ID LIKE '%' || #{keyword} || '%' OR m.NICKNAME LIKE '%' || #{keyword} || '%' OR m.EMAIL LIKE '%' || #{keyword} || '%' )
AND m.ROLE = #{role}
AND m.STATUS = #{status}
AND m.CREATED_AT >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND m.CREATED_AT <= TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1 - 1/86400
) SELECT * FROM PagedMembers WHERE rnum > #{offset} AND rnum <= #{offset} + #{size}

mapper.update:
UPDATE MEMBER
SET 
    STATUS = 'SUSPENDED',
    SUSPENSION_END_DATE = SYSDATE + #{days}
WHERE MEMBER_ID = #{id}
